import java.sql.*;
public class AutoCommitDefault {
    public static void main(String[] args) throws Exception {
        // Simulating connection behavior
        // By JDBC spec, new connections have autoCommit=true by default
        boolean autoCommit = true;  // default
        System.out.println(autoCommit);
        autoCommit = false;
        System.out.println(autoCommit);
        System.out.println(Connection.TRANSACTION_READ_COMMITTED);
    }
}
